1	const PROCESSING_FEE = 5;
2	const RUNE_BASE_PREMIUM = 25;
3	const BLOCK_OF_THREE_DISCOUNT = 15;
4	
5	type Scenario = { steps: { op: string; items: unknown[] }[] };
6	
7	export function runScenario(scenario: unknown): unknown {
8	  const items = (scenario as Scenario).steps[0].items as { type: string }[];
9	  const itemsSubtotal = items.length * RUNE_BASE_PREMIUM;
10	  const isBlockOfThreeAlike =
11	    items.length === 3 && items.every((item) => item.type === items[0].type);
12	  const blockDiscount = isBlockOfThreeAlike ? BLOCK_OF_THREE_DISCOUNT : 0;
13	  const basePremium = itemsSubtotal - blockDiscount;
14	  return { results: [{ premium: basePremium + PROCESSING_FEE }] };
15	}
